"use client";

import React, { useState, useMemo } from 'react';
import { 
  Search, Trophy, Home, List, Users, 
  ChevronRight, Settings, Crown, 
  Activity, ChevronLeft, Copy, Globe
} from 'lucide-react';
import playersData from '../data/players.json';

export default function McTierUltimate() {
  const [search, setSearch] = useState("");
  const [activeTab, setActiveTab] = useState("Overall");
  const [isExpanded, setIsExpanded] = useState(false);
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText("play.nordenmc.com"); // Replace this later!
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const getTierStyles = (tier: string) => {
    if (tier?.includes('HT1')) return 'text-red-500 border-red-500/30 bg-red-500/5 shadow-[0_0_15px_rgba(239,68,68,0.2)]';
    if (tier?.includes('LT1')) return 'text-cyan-400 border-cyan-500/30 bg-cyan-500/5 shadow-[0_0_15px_rgba(6,182,212,0.2)]';
    return 'text-purple-400 border-purple-500/30 bg-purple-500/5';
  };

  const filteredPlayers = useMemo(() => {
    const data = Array.isArray(playersData) ? playersData : [];
    return data.filter((p: any) => p.name?.toLowerCase().includes(search.toLowerCase()));
  }, [search]);

  return (
    <div className="flex min-h-screen bg-[#050507] text-[#e1e1e3] font-sans overflow-x-hidden">
      
      {/* SIDEBAR */}
      <aside className={`hidden lg:flex flex-col py-8 border-r border-white/5 bg-[#08080a] sticky top-0 h-screen transition-all duration-300 z-[100] ${isExpanded ? 'w-64 px-6' : 'w-20 items-center'}`}>
        <div onClick={() => setIsExpanded(!isExpanded)} className="mb-10 cursor-pointer text-cyan-500 bg-cyan-500/10 p-3 rounded-2xl border border-cyan-500/20 hover:scale-105 transition-all">
          {isExpanded ? <ChevronLeft size={28} /> : <Trophy size={28} />}
        </div>
        <nav className="flex flex-col gap-8 text-gray-600 w-full">
          {[{ icon: <Home size={24} />, label: "Home" }, { icon: <List size={24} />, label: "Tiers", active: true }, { icon: <Users size={24} />, label: "Staff" }].map((item, idx) => (
            <div key={idx} className={`flex items-center gap-4 cursor-pointer hover:text-cyan-400 transition-all ${isExpanded ? '' : 'justify-center'}`}>
              <div className={item.active ? 'text-cyan-500' : ''}>{item.icon}</div>
              {isExpanded && <span className="font-bold">{item.label}</span>}
            </div>
          ))}
        </nav>
      </aside>

      <div className="flex-1 flex flex-col">
        {/* TOP STATUS BAR */}
        <div className="bg-cyan-500/10 border-b border-cyan-500/20 py-2 px-8 flex items-center justify-center gap-6 text-[10px] font-black uppercase tracking-[0.2em] text-cyan-400">
          <div className="flex items-center gap-2"><div className="w-1.5 h-1.5 rounded-full bg-cyan-500 animate-pulse" /> Server Online</div>
          <div className="w-px h-3 bg-white/10" />
          <div className="flex items-center gap-2 underline cursor-pointer hover:text-white" onClick={handleCopy}>
            {copied ? "IP COPIED!" : "IP: PLAY.NORDENMC.COM"} <Copy size={10} />
          </div>
        </div>

        <header className="h-20 border-b border-white/5 bg-[#050507]/80 backdrop-blur-xl sticky top-0 z-50 px-8 flex items-center justify-between">
          <h1 className="text-2xl font-black italic text-white">NORDEN<span className="text-cyan-500">MC</span></h1>
          <div className="relative w-72 md:w-96">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
            <input type="text" placeholder="Search rankings..." className="w-full bg-[#0f0f13] border border-white/5 rounded-2xl py-2.5 pl-12 pr-4 outline-none focus:border-cyan-500/40 transition-all text-sm" value={search} onChange={(e) => setSearch(e.target.value)} />
          </div>
        </header>

        <main className="p-6 md:p-12 max-w-7xl mx-auto w-full">
          {/* TOP 3 CARDS */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
            {filteredPlayers.slice(0, 3).map((p, i) => (
              <div key={p.name} className="bg-gradient-to-br from-[#111115] to-[#08080a] border border-white/5 p-6 rounded-[2rem] flex items-center gap-4 group hover:border-cyan-500/30 transition-all">
                <img src={`https://mc-heads.net/avatar/${p.name}/100`} className="w-14 h-14 rounded-xl border border-white/10 group-hover:scale-110 transition-transform" />
                <div>
                  <h3 className="font-bold text-lg flex items-center gap-2">{p.name} <Crown size={14} className={i === 0 ? "text-yellow-500" : "text-gray-500"} /></h3>
                  <p className="text-[10px] text-cyan-500/60 font-black uppercase tracking-tighter">Global Rank #{p.rank}</p>
                </div>
              </div>
            ))}
          </div>

          {/* PLAYER LIST */}
          <div className="bg-[#0a0a0d] border border-white/5 rounded-[2rem] overflow-hidden shadow-2xl">
            {filteredPlayers.map((player: any) => (
              <div key={player.name} className="grid grid-cols-12 gap-4 p-6 items-center hover:bg-white/[0.01] transition-all border-b border-white/[0.02]">
                <div className="col-span-1 text-2xl font-black italic text-gray-800">0{player.rank}</div>
                <div className="col-span-7 flex items-center gap-4">
                  <img src={`https://mc-heads.net/avatar/${player.name}/100`} className="w-12 h-12 rounded-xl" />
                  <div>
                    <div className="font-bold text-lg">{player.name}</div>
                    <div className="text-[9px] text-gray-500 uppercase font-bold flex items-center gap-1"><Activity size={10} /> {player.kit} • Online</div>
                  </div>
                </div>
                <div className="col-span-4 flex justify-end">
                  <div className={`px-6 py-2 rounded-xl font-black italic border ${getTierStyles(player.tier)}`}>{player.tier}</div>
                </div>
              </div>
            ))}
          </div>
        </main>
      </div>
    </div>
  );
}